const Web3 = require('web3');
require('dotenv').config();

// Configuration
const providerUrl = process.env.PROVIDER_URL;
const privateKey = process.env.PRIVATE_KEY;

// Initialize Web3 with the Ethereum node URL
const web3 = new Web3(new Web3.providers.HttpProvider(providerUrl));

// Get wallet account from private key
const account = web3.eth.accounts.privateKeyToAccount(privateKey);

// Function to send ETH
async function sendEth(toAddress, amountInWei) {
  const transaction = {
    from: account.address,
    to: toAddress,
    value: amountInWei,
  };

  const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
  const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);

  console.log('Transaction successful with hash:', receipt.transactionHash);
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
  const contract = new web3.eth.Contract(abi, contractAddress);
  const gasPrice = await web3.eth.getGasPrice();
  
  // Example function call - Adjust according to your smart contract's functions
  const method = contract.methods[functionName](...params);

  const data = method.encodeABI();
  const transaction = {
    from: account.address,
    to: contractAddress,
    gas: await method.estimateGas({ from: account.address }),
    gasPrice: gasPrice,
    data: data,
  };

  const signedTransaction = await web3.eth.accounts.signTransaction(transaction, privateKey);
  const receipt = await web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);

  console.log('Contract interaction successful with hash:', receipt.transactionHash);
}

